async function safeFetch() {
  try {
    const response = await fetch('https://api.example.com/bad-url');

    // CRITICAL: Manually check for HTTP errors!
    if (!response.ok) {
      // This throws the error down to the catch block below
      throw new Error(`HTTP Error! Status: ${response.status}`); 
    }

    const data = await response.json();
    return data;

  } catch (error) {
    // This block now catches TWO things:
    // 1. Literal network failures (no internet)
    // 2. The manual HTTP error we threw above
    console.error('Fetch failed:', error.message);
  }
}

